#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    return *(int *)b - *(int *)a;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        long long sum = 0;
        int *gains = (int *)malloc(N * sizeof(int));
        int posCnt = 0;
        for (int i = 0; i < N; ++i) {
            int a; scanf("%d", &a);
            sum += a;
            int g = 7 - 2 * a;
            if (g > 0) gains[posCnt++] = g;
        }
        qsort(gains, posCnt, sizeof(int), cmp_desc);
        for (int i = 0; i < K && i < posCnt; ++i) sum += gains[i];
        printf("%lld\n", sum);
        free(gains);
    }
    return 0;
}

